const BASE_URL = '/api/products';

// GET все товары
export const getProducts = () =>
  fetch(BASE_URL).then(r => r.json());

// Создать товар с картинкой (image может быть null)
export const createProduct = (data, image) => {
  const formData = new FormData();
  formData.append('title', data.title);
  formData.append('category', data.category);
  formData.append('description', data.description);
  formData.append('price', data.price);
  formData.append('stock', data.stock);
  if (image) formData.append('image', image);

  return fetch(BASE_URL, {
    method: 'POST',
    body: formData
  }).then(r => r.json());
};

// Обновить товар (PATCH) с возможной новой картинкой
export const updateProduct = (id, data, image) => {
  const formData = new FormData();
  if (data.title !== undefined) formData.append('title', data.title);
  if (data.category !== undefined) formData.append('category', data.category);
  if (data.description !== undefined) formData.append('description', data.description);
  if (data.price !== undefined) formData.append('price', data.price);
  if (data.stock !== undefined) formData.append('stock', data.stock);
  if (image) formData.append('image', image);

  return fetch(`${BASE_URL}/${id}`, {
    method: 'PATCH',
    body: formData
  }).then(r => r.json());
};

// Удалить товар
export const deleteProduct = async (id) => {
  console.log('DELETE вызван для id:', id);
  const res = await fetch(`${BASE_URL}/${id}`, {
    method: 'DELETE'
  });
  console.log('DELETE статус:', res.status);
  if (res.status === 204 || res.ok) {
    return true;
  }
  throw new Error(`Удаление не удалось: ${res.status}`);
};
